  // Premium atmospheric background. It uses the darker #103783 direction as the stage base,
  // with #9bafd9 / #ebf4f5 only as soft light so the diploma stays cinematic and legible.
  function buildSceneBackgroundTexture(){
    const size = 1536;
    const {c,ctx} = mkCanvas(size,size);

    const base = ctx.createLinearGradient(0,0,size,size);
    base.addColorStop(0.00,'#02050e');
    base.addColorStop(0.36,'#071632');
    base.addColorStop(1.00,'#103783');
    ctx.fillStyle = base;
    ctx.fillRect(0,0,size,size);

    function radial(cx,cy,r0,r1,stops,mode){
      ctx.save();
      if(mode) ctx.globalCompositeOperation = mode;
      const g = ctx.createRadialGradient(cx,cy,r0,cx,cy,r1);
      stops.forEach(s=>g.addColorStop(s[0],s[1]));
      ctx.fillStyle = g;
      ctx.fillRect(0,0,size,size);
      ctx.restore();
    }

    radial(size*0.28,size*0.16,0,size*0.64, [
      [0.00,'rgba(181,198,224,0.36)'],
      [0.28,'rgba(155,175,217,0.16)'],
      [0.62,'rgba(155,175,217,0.035)'],
      [1.00,'rgba(155,175,217,0.00)']
    ], 'lighter');
    radial(size*0.80,size*0.35,0,size*0.70, [
      [0.00,'rgba(16,55,131,0.62)'],
      [0.48,'rgba(16,55,131,0.18)'],
      [1.00,'rgba(16,55,131,0.00)']
    ], 'source-over');
    radial(size*0.50,size*0.78,0,size*0.52, [
      [0.00,'rgba(216,181,109,0.14)'],
      [0.34,'rgba(216,181,109,0.045)'],
      [1.00,'rgba(216,181,109,0.00)']
    ], 'lighter');

    ctx.save();
    ctx.globalCompositeOperation = 'screen';
    const sweep = ctx.createLinearGradient(size*0.18,0,size*0.82,size);
    sweep.addColorStop(0.00,'rgba(235,244,245,0.00)');
    sweep.addColorStop(0.42,'rgba(235,244,245,0.07)');
    sweep.addColorStop(0.60,'rgba(235,244,245,0.00)');
    ctx.fillStyle = sweep;
    ctx.fillRect(0,0,size,size);
    ctx.restore();

    const vignette = ctx.createRadialGradient(size*0.50,size*0.45,size*0.24,size*0.50,size*0.50,size*0.78);
    vignette.addColorStop(0.00,'rgba(0,0,0,0.00)');
    vignette.addColorStop(0.62,'rgba(0,0,0,0.18)');
    vignette.addColorStop(1.00,'rgba(0,0,0,0.76)');
    ctx.fillStyle = vignette;
    ctx.fillRect(0,0,size,size);

    // Tiny film grain prevents flat banding on large monitors without reading as noise.
    const grain = ctx.getImageData(0,0,size,size);
    const data = grain.data;
    let seed = 28173;
    function rand(){ seed = (seed * 1664525 + 1013904223) >>> 0; return seed / 4294967296; }
    for(let i=0;i<data.length;i+=4){
      const n = (rand() - 0.5) * 4;
      data[i] = Math.max(0, Math.min(255, data[i] + n));
      data[i+1] = Math.max(0, Math.min(255, data[i+1] + n));
      data[i+2] = Math.max(0, Math.min(255, data[i+2] + n));
    }
    ctx.putImageData(grain,0,0);

    const tex = new THREE.CanvasTexture(c);
    tex.encoding = THREE.sRGBEncoding;
    tex.minFilter = THREE.LinearFilter;
    tex.magFilter = THREE.LinearFilter;
    tex.needsUpdate = true;
    return tex;
  }
  scene.background = buildSceneBackgroundTexture();


